class Solution:
    def minFlips(self, mat) -> int:
        from collections import deque
        m, n = len(mat), len(mat[0])
        def encode(g):
            state = 0
            for i in range(m):
                for j in range(n):
                    state |= g[i][j] << (i * n + j)
            return state
        start = encode(mat)
        if start == 0:
            return 0
        visited = {start}
        queue = deque([(start, 0)])
        dirs = [(0,0),(0,1),(0,-1),(1,0),(-1,0)]
        while queue:
            state, steps = queue.popleft()
            for i in range(m):
                for j in range(n):
                    nstate = state
                    for di, dj in dirs:
                        ni, nj = i + di, j + dj
                        if 0 <= ni < m and 0 <= nj < n:
                            nstate ^= 1 << (ni * n + nj)
                    if nstate == 0:
                        return steps + 1
                    if nstate not in visited:
                        visited.add(nstate)
                        queue.append((nstate, steps + 1))
        return -1

