var minFlips = function(mat) {
    const m = mat.length, n = mat[0].length;
    let start = 0;
    for (let i = 0; i < m; i++)
        for (let j = 0; j < n; j++)
            start |= mat[i][j] << (i * n + j);
    if (start === 0) return 0;
    const visited = new Set([start]);
    const queue = [[start, 0]];
    const dirs = [[0,0],[0,1],[0,-1],[1,0],[-1,0]];
    let qi = 0;
    while (qi < queue.length) {
        const [state, steps] = queue[qi++];
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                let nstate = state;
                for (const [di, dj] of dirs) {
                    const ni = i + di, nj = j + dj;
                    if (ni >= 0 && ni < m && nj >= 0 && nj < n)
                        nstate ^= 1 << (ni * n + nj);
                }
                if (nstate === 0) return steps + 1;
                if (!visited.has(nstate)) {
                    visited.add(nstate);
                    queue.push([nstate, steps + 1]);
                }
            }
        }
    }
    return -1;
};
